import javax.jws.WebMethod;
import javax.jws.WebParam;
import javax.jws.WebResult;
import javax.jws.soap.SOAPBinding;
import javax.xml.ws.Holder;

@SOAPBinding(style = SOAPBinding.Style.RPC)
public interface OrderProcessor {

    @WebMethod
    public void processOrder(
            @WebParam(name = "item") Holder<Item> item,
            @WebParam(name = "quantity") Holder<Integer> quantity,
            @WebResult(name = "totalPrice") Holder<Double> totalPrice);

}

class Item {
    String name;
    double price;

    public Item(String name, double price) {
        this.name = name;
        this.price = price;
    }

    public String getName() {
        return name;
    }

    public void setName(String name) {
        this.name = name;
    }

    public double getPrice() {
        return price;
    }

    public void setPrice(double price) {
        this.price = price;
    }
}

import javax.xml.namespace.QName;
import javax.xml.soap.SOAPMessage;
import javax.xml.soap.SOAPBody;
import javax.xml.soap.MessageFactory;
import javax.xml.soap.NameSpaceMapping;
import java.io.StringReader;

class OrderProcessorImpl implements OrderProcessor {

    @Override
    public void processOrder(
            Holder<Item> item,
            Holder<Integer> quantity,
            Holder<Double> totalPrice) {
        try {
            MessageFactory messageFactory = MessageFactory.newInstance();
            SOAPMessage soapMessage = messageFactory.createMessage(null, new StringReader(item.value.getName()));
            SOAPBody body = soapMessage.getSOAPBody();

            QName nameSpace = new QName("http://b2b.ordering.system.com/", "order");

            Item orderItem = parseItem(body.getDocumentElement().getElementsByTagName(nameSpace).item(0));
            int quantityVal = getQuantityValue(quantity);
            double totalPriceVal = calculateTotalPrice(orderItem.getPrice(), quantityVal);

            item.value = orderItem;
            quantity.value = quantityVal;
            totalPrice.value = totalPriceVal;

        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private Item parseItem(org.w3c.dom.Element element) {
        String name = element.getElementsByTagName("name").item(0).getTextContent();
        double price = Double.parseDouble(element.getElementsByTagName("price").item(0).getTextContent());
        return new Item(name, price);
    }

    private int getQuantityValue(Holder<Integer> quantity) {
        return Integer.parseInt(quantity.value.toString());
    }

    private double calculateTotalPrice(double price, int quantity) {
        return price * quantity;
    }
}